server {
    listen 443 ssl;
    server_name {{domain}};

    ssl_certificate /etc/ssl/certs/{{domain}}.crt;
    ssl_certificate_key /etc/ssl/private/{{domain}}.key;

    ssl_protocols TLSv1.2 TLSv1.3;
    ssl_ciphers HIGH:!aNULL:!MD5;

    location / {
        proxy_pass http://localhost:{{port}};
    }
}
